# Exemple de scheduling avec un scheduler FIFO en C

create(struct Process, *processes, size) {
    size = sizeof(struct Process);
    for (int i = 0; i < size; i++) {
        processes[i].priority = 0;
        processes[i].readyTime = -1;
    }
}

# Fonction d'interruption pour le scheduler FIFO
int syscall(int syscall_number) {
    // Traite l'appel système
    int ready_time = processes[0].readyTime;
    if (ready_time != -1) {
        return 0; // Ready
    } else {
        return 1; // Non-Ready
    }
}

# Exemple d'utilisation du scheduler FIFO avec des processus à haute priorité
processes[0].priority = 2;
processes[0].readyTime = 10;
priority_queue<int> pq; // Pile de priorités
pq.push(0);
pq.push(1);
pq.push(2);
pq.push(3);
pq.push(4);
pq.push(5);
pq.push(6);
while (!pq.empty()) {
    int index = pq.top();
    pq.pop();
    syscall(index);
}
